CREATE CACHED TABLE IF NOT EXISTS "CLIENT_HISTORY" (
    "ID" BIGINT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
    "TIMESTAMP" TIMESTAMP NOT NULL,
    "TYPE" VARCHAR(256) NOT NULL,
    "OBJECTTYPE" INTEGER NOT NULL,
    "TAGNAME" VARCHAR(1024) NULL,
    "ELEMENTID" VARCHAR(1024) NULL,
    "NODENAME" VARCHAR(4096) NULL,
    "URL" VARCHAR(8192) NULL,
    "XPATH" VARCHAR(8192) NULL,
    "HREF" VARCHAR(8192) NULL,
    "TEXT" VARCHAR(8192) NULL,
    "TAGTYPE" VARCHAR(256) NULL,
    "FORMID" INTEGER NULL,
    "COUNT" INTEGER NULL,
);
